// GET — Retrieve data (most common)
fetch('https://api.example.com/users')
  .then(res => res.json())
  .then(data => console.log(data));

// POST — Create new data
fetch('https://api.example.com/users', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ name: 'Raj', email: 'raj@example.com' })
});

// PUT — Update existing data
// DELETE — Remove data

// REQUEST has 3 parts:
// 1. Method + URL: GET /api/users
// 2. Headers: { Authorization: 'Bearer token123' }
// 3. Body (for POST/PUT): { name: 'Raj' }

// RESPONSE has 3 parts:
// 1. Status: 200 OK
// 2. Headers: { Content-Type: 'application/json' }
// 3. Body: [{ id: 1, name: 'Raj' }, ...]

// In JavaScript:
let response = await fetch('/api/users');
let status = response.status;     // 200
let headers = response.headers;   // Headers object
let data = await response.json(); // The actual data

// HTTP:  GET /login → sends password in PLAIN TEXT
//         Anyone on the network can read it!

// HTTPS: GET /login → password is ENCRYPTED
//         Even if intercepted, it's unreadable

// Signs of HTTPS:
// 1. URL starts with https://
// 2. Padlock icon in browser
// 3. SSL certificate (you can click to view it)

// Always use HTTPS in production!
